<?php
namespace App\Services;
use App\Core\Database;
final class InspectionPacketService{
 public function render(int $id):array{PdfService::assertAvailable();$pdo=Database::connection();$q=$pdo->prepare("SELECT i.*,t.name template_name,j.job_number,c.display_name customer_name,p.address1,p.city,p.state,p.postal_code,u.name completed_name FROM inspections i JOIN inspection_templates t ON t.id=i.inspection_template_id LEFT JOIN jobs j ON i.entity_type='job' AND j.id=i.entity_id LEFT JOIN customers c ON c.id=j.customer_id LEFT JOIN properties p ON p.id=j.property_id LEFT JOIN users u ON u.id=i.completed_by WHERE i.id=?");$q->execute([$id]);$inspection=$q->fetch();if(!$inspection)throw new \RuntimeException('Inspection not found.');$items=$pdo->prepare('SELECT ti.label,ti.field_type,r.response_text FROM inspection_template_items ti LEFT JOIN inspection_responses r ON r.inspection_template_item_id=ti.id AND r.inspection_id=? WHERE ti.inspection_template_id=? ORDER BY ti.sort_order,ti.id');$items->execute([$id,$inspection['inspection_template_id']]);$attachments=$pdo->prepare("SELECT * FROM inspection_attachments WHERE inspection_id=? AND deleted_at IS NULL ORDER BY created_at");$attachments->execute([$id]);ob_start();include dirname(__DIR__).'/views/pdf/inspection-packet.php';$html=(string)ob_get_clean();$dompdf=new \Dompdf\Dompdf(['isRemoteEnabled'=>false]);$dompdf->loadHtml($html);$dompdf->setPaper('letter');$dompdf->render();return ['bytes'=>$dompdf->output(),'filename'=>'inspection-'.$id.'.pdf','inspection'=>$inspection];}
}
